import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function CreateProject() {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    skills_required: '',
    budget_min: '',
    budget_max: '',
    duration_days: '',
    status: 'open'
  });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access');
      await axios.post('http://127.0.0.1:8000/api/projects/', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('Project created successfully!');
      navigate('/projects');
    } catch (error) {
      console.error('Error creating project:', error);
      alert('Failed to create project');
    }
  };

  return (
    <div className="container">
      <h2>Create New Project</h2>
      <form onSubmit={handleSubmit}>
        <input name="title" placeholder="Title" onChange={handleChange} required />
        <textarea name="description" placeholder="Description" onChange={handleChange} required />
        <input name="skills_required" placeholder="Skills (comma separated)" onChange={handleChange} required />
        <input type="number" name="budget_min" placeholder="Min Budget" onChange={handleChange} required />
        <input type="number" name="budget_max" placeholder="Max Budget" onChange={handleChange} required />
        <input type="number" name="duration_days" placeholder="Duration (days)" onChange={handleChange} required />
        <button type="submit">Create Project</button>
      </form>
    </div>
  );
}

export default CreateProject;
